mkdir -p /tmp/nint_test && cd /tmp/nint_test && dotnet new console --force -q && cat << 'EOF' > Program.cs
using System;

unsafe {
    Span<nint> a = stackalloc nint[4];
    a[0] = 42;
    a[1] = nint.MaxValue;
    Console.WriteLine($"nint span: [{a[0]}, {a[1]}], size={sizeof(nint)} bytes");

    Span<nuint> b = stackalloc nuint[4];
    b[0] = 123;
    b[1] = nuint.MaxValue;
    Console.WriteLine($"nuint span: [{b[0]}, {b[1]}], size={sizeof(nuint)} bytes");
}

Console.WriteLine("Success!");
EOF
# Enable unsafe and set lang version
sed -i 's|</PropertyGroup>|<AllowUnsafeBlocks>true</AllowUnsafeBlocks>\n</PropertyGroup>|' nint_test.csproj
dotnet run 2>&1

